class Solution:
    def maximumSegmentSum(self, nums, removeQueries):
        n = len(nums)
        arr = nums[:]
        ans = []
        for q in removeQueries:
            arr[q] = 0
            best = 0
            cur = 0
            for v in arr:
                if v == 0:
                    cur = 0
                else:
                    cur += v
                    if cur > best:
                        best = cur
            ans.append(best)
        return ans

