class Solution:
    def maximumSegmentSum(self, nums, removeQueries):
        n = len(nums)
        parent = list(range(n))
        seg = [0] * n
        active = [False] * n
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        ans = [0] * n
        best = 0
        for i in range(n - 1, 0, -1):
            idx = removeQueries[i]
            active[idx] = True
            seg[idx] = nums[idx]
            for nb in (idx - 1, idx + 1):
                if 0 <= nb < n and active[nb]:
                    ra, rb = find(idx), find(nb)
                    if ra != rb:
                        parent[rb] = ra
                        seg[ra] += seg[rb]
            best = max(best, seg[find(idx)])
            ans[i - 1] = best
        return ans

