var maximumSegmentSum = function(nums, removeQueries) {
    const n = nums.length;
    const parent = Array.from({length: n}, (_, i) => i);
    const seg = new Array(n).fill(0);
    const active = new Array(n).fill(false);
    const find = (x) => {
        while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; }
        return x;
    };
    const ans = new Array(n).fill(0);
    let best = 0;
    for (let i = n - 1; i > 0; i--) {
        const idx = removeQueries[i];
        active[idx] = true;
        seg[idx] = nums[idx];
        for (const nb of [idx - 1, idx + 1]) {
            if (nb >= 0 && nb < n && active[nb]) {
                const ra = find(idx), rb = find(nb);
                if (ra !== rb) { parent[rb] = ra; seg[ra] += seg[rb]; }
            }
        }
        const r = find(idx);
        if (seg[r] > best) best = seg[r];
        ans[i - 1] = best;
    }
    return ans;
};
